const body = $input.first().json.body;
const { contactId, followUp } = body;

if (!contactId || !followUp) {
  throw new Error('Missing contactId or followUp in payload');
}

const { followUpEmail, nextTask, coachingNote } = followUp;

if (!followUpEmail || !nextTask) {
  throw new Error('Malformed follow-up structure');
}

// Calculate task due date
const dueDate = new Date();
dueDate.setDate(dueDate.getDate() + (nextTask.daysFromNow || 1));

return [{
  json: {
    contactId,
    followUpEmail,
    nextTask: {
      ...nextTask,
      dueDate: dueDate.toISOString().split('T')[0]
    },
    coachingNote,
    processedAt: new Date().toISOString()
  }
}];

const data = $('Parse Follow-up Payload').item.json;

// Build notification for the sales rep
const keyPoints = (data.followUpEmail.keyPoints || []).map(p => `• ${p}`).join('\n');

return [{
  json: {
    text: `🤖 *AI Follow-up Suggestion Ready*`,
    blocks: [
      {
        type: 'section',
        text: {
          type: 'mrkdwn',
          text: `*🤖 AI Follow-up Generated* for Contact ${data.contactId}\n*Coaching Note:* _${data.coachingNote}_`
        }
      },
      {
        type: 'section',
        text: {
          type: 'mrkdwn',
          text: `*📧 Suggested Email Subject:* ${data.followUpEmail.subject}\n*Key Points:*\n${keyPoints}`
        }
      },
      {
        type: 'section',
        text: {
          type: 'mrkdwn',
          text: `*✅ Task Created:* "${data.nextTask.title}" due ${data.nextTask.dueDate} (${data.nextTask.priority} priority)`
        }
      }
    ]
  }
}];
